#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

/* Simple open‑addressing hash table for 64‑bit keys */
typedef struct {
    int64_t key;
    int64_t cnt;
    char used;
} Entry;

static uint64_t hash_uint64(uint64_t x) {
    const uint64_t MULT = 11400714819323198485ULL;
    return x * MULT;
}

static void ht_insert(Entry *table, size_t size, int64_t key) {
    uint64_t h = hash_uint64((uint64_t)key);
    size_t idx = (size_t)(h & (size - 1));
    while (table[idx].used && table[idx].key != key) {
        idx = (idx + 1) & (size - 1);
    }
    if (!table[idx].used) {
        table[idx].used = 1;
        table[idx].key = key;
        table[idx].cnt = 1;
    } else {
        table[idx].cnt++;
    }
}

static int64_t ht_get(const Entry *table, size_t size, int64_t key) {
    uint64_t h = hash_uint64((uint64_t)key);
    size_t idx = (size_t)(h & (size - 1));
    while (table[idx].used && table[idx].key != key) {
        idx = (idx + 1) & (size - 1);
    }
    if (!table[idx].used) return 0;
    return table[idx].cnt;
}

int main(void) {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long K;
        scanf("%d %lld", &N, &K);
        long long *a = (long long *)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);

        /* hash table size: next power of two >= 2*(N+1) */
        size_t size = 1;
        while (size < 2 * (size_t)(N + 1)) size <<= 1;
        Entry *table = (Entry *)calloc(size, sizeof(Entry));

        ht_insert(table, size, 0); // prefix sum 0 occurs once
        long long pref = 0;
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            pref += a[i];
            ans += ht_get(table, size, pref - K);
            ht_insert(table, size, pref);
        }
        printf("%lld\n", ans);
        free(a);
        free(table);
    }
    return 0;
}

