int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin >> T)) return 0;
    while (T--) {
        int N; long long K;
        cin >> N >> K;
        vector<long long> a(N);
        for (auto &x : a) cin >> x;
        unordered_map<long long,long long> freq;
        freq.reserve(N * 2);
        freq[0] = 1;
        long long pref = 0, ans = 0;
        for (long long x : a) {
            pref += x;
            ans += freq[pref - K];
            ++freq[pref];
        }
        cout << ans << '\n';
    }
    return 0;
}

