const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(data[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const N = Number(data[idx++]);
  const K = Number(data[idx++]);
  const map = new Map();
  map.set(0, 1);
  let pref = 0;
  let ans = 0;
  for (let i = 0; i < N; ++i) {
    pref += Number(data[idx++]);
    const need = pref - K;
    if (map.has(need)) ans += map.get(need);
    map.set(pref, (map.get(pref) || 0) + 1);
  }
  results.push(String(ans));
}
